{
    public AsyncEnumerator GetAsyncEnumerator(System.Threading.CancellationToken token \= default)
    {
        throw null;
    }

    public sealed class AsyncEnumerator : System.IAsyncDisposable
    {
        public int Current { get \=> throw null; }
